  created_at, updated_at
) VALUES (
  'sang-tao-khong-bat-dau-tu-tham-vong', 'post',
  'Sáng tạo không bắt đầu từ tham vọng mà từ sự thấy rõ',
  'Sáng tạo không bắt đầu từ tham vọng mà từ sự thấy rõ',
  'Creativity does not begin with ambition but with clarity',
  'Điều tạo nên giá trị bền vững không phải là làm cho thật nhiều để được chú ý, mà là thấy đúng nhu cầu thật và tạo ra điều cần được sinh ra.',
  'Điều tạo nên giá trị bền vững không phải là làm cho thật nhiều để được chú ý, mà là thấy đúng nhu cầu thật và tạo ra điều cần được sinh ra.',
  'Lasting value does not come from producing more in order to be noticed, but from seeing a real need and bringing forth what truly deserves to exist.',
  '<p>Nhiều người bước vào sáng tạo với áp lực phải mới, phải lạ, phải khác, phải khiến người khác chú ý. Áp lực ấy có thể tạo ra tốc độ, nhưng không phải lúc nào tạo ra chiều sâu. Khi sáng tạo bị dẫn dắt bởi tham vọng được công nhận, ta dễ hỏi sai câu hỏi: làm sao để nổi bật hơn, thay vì điều gì đang thật sự cần được làm rõ.</p><p>Sáng tạo ở tầng sâu hơn bắt đầu từ sự thấy rõ. Thấy rõ một vấn đề chưa được gọi tên. Thấy rõ một nỗi đau mà nhiều người đang chịu nhưng chưa biết diễn đạt. Thấy rõ một khoảng trống trong đời sống mà sản phẩm, bài viết, chương trình hay cộng đồng có thể chạm đến một cách tử tế.</p><p>Một người viết có thể bắt đầu từ tham vọng trở thành người nổi tiếng. Nhưng nếu chỉ đi từ tham vọng đó, bài viết rất dễ trở thành tiếng ồn mới trong biển tiếng ồn cũ. Một người viết khác bắt đầu bằng việc lắng nghe: vì sao nhiều người trẻ đọc rất nhiều nhưng vẫn thấy rỗng? Vì sao họ thành công bên ngoài nhưng vẫn mệt bên trong? Vì sao họ có nhiều lựa chọn nhưng lại không biết chọn hướng nào?</p><p>Trong đời sống, nhu cầu thật thường không nằm trên bề mặt. Người ta nói cần động lực, nhưng có khi điều họ cần là được nghỉ mà không thấy tội lỗi. Người ta nói cần kỹ năng giao tiếp, nhưng có khi điều họ cần là can đảm nói thật mà không phá vỡ sự tôn trọng. Người ta nói cần thành công, nhưng có khi điều họ cần là một định nghĩa thành công không phản bội sức khỏe, gia đình và phẩm giá.</p><p>Điều này không phủ nhận tham vọng. Tham vọng có thể là năng lượng tốt nếu được đặt đúng chỗ. Nhưng tham vọng cần phục vụ sự thấy rõ, không thay thế sự thấy rõ. Khi tham vọng đứng trước, ta dễ ép cuộc đời phải chứng minh mình đặc biệt. Khi sự thấy rõ đứng trước, ta học cách để công việc phục vụ một giá trị lớn hơn sự khẳng định cá nhân.</p><p>Đường Sao Tỏa Sáng chọn đi theo hướng sáng tạo chậm và sâu. Một bài viết, một kịch bản, một sự kiện hay một chương trình không cần chỉ để lấp lịch đăng. Nó cần trả lời câu hỏi: điều này có giúp ai đó nhìn rõ hơn, sống thật hơn, đi tử tế hơn không?</p><p>Trước khi tạo ra điều tiếp theo, hãy thử dừng lại và hỏi: mình đang muốn được nhìn thấy, hay mình đang thật sự nhìn thấy một điều cần được chăm sóc?</p>',
  '<p>Nhiều người bước vào sáng tạo với áp lực phải mới, phải lạ, phải khác, phải khiến người khác chú ý. Áp lực ấy có thể tạo ra tốc độ, nhưng không phải lúc nào tạo ra chiều sâu. Khi sáng tạo bị dẫn dắt bởi tham vọng được công nhận, ta dễ hỏi sai câu hỏi: làm sao để nổi bật hơn, thay vì điều gì đang thật sự cần được làm rõ.</p><p>Sáng tạo ở tầng sâu hơn bắt đầu từ sự thấy rõ. Thấy rõ một vấn đề chưa được gọi tên. Thấy rõ một nỗi đau mà nhiều người đang chịu nhưng chưa biết diễn đạt. Thấy rõ một khoảng trống trong đời sống mà sản phẩm, bài viết, chương trình hay cộng đồng có thể chạm đến một cách tử tế.</p><p>Một người viết có thể bắt đầu từ tham vọng trở thành người nổi tiếng. Nhưng nếu chỉ đi từ tham vọng đó, bài viết rất dễ trở thành tiếng ồn mới trong biển tiếng ồn cũ. Một người viết khác bắt đầu bằng việc lắng nghe: vì sao nhiều người trẻ đọc rất nhiều nhưng vẫn thấy rỗng? Vì sao họ thành công bên ngoài nhưng vẫn mệt bên trong? Vì sao họ có nhiều lựa chọn nhưng lại không biết chọn hướng nào?</p><p>Trong đời sống, nhu cầu thật thường không nằm trên bề mặt. Người ta nói cần động lực, nhưng có khi điều họ cần là được nghỉ mà không thấy tội lỗi. Người ta nói cần kỹ năng giao tiếp, nhưng có khi điều họ cần là can đảm nói thật mà không phá vỡ sự tôn trọng. Người ta nói cần thành công, nhưng có khi điều họ cần là một định nghĩa thành công không phản bội sức khỏe, gia đình và phẩm giá.</p><p>Điều này không phủ nhận tham vọng. Tham vọng có thể là năng lượng tốt nếu được đặt đúng chỗ. Nhưng tham vọng cần phục vụ sự thấy rõ, không thay thế sự thấy rõ. Khi tham vọng đứng trước, ta dễ ép cuộc đời phải chứng minh mình đặc biệt. Khi sự thấy rõ đứng trước, ta học cách để công việc phục vụ một giá trị lớn hơn sự khẳng định cá nhân.</p><p>Đường Sao Tỏa Sáng chọn đi theo hướng sáng tạo chậm và sâu. Một bài viết, một kịch bản, một sự kiện hay một chương trình không cần chỉ để lấp lịch đăng. Nó cần trả lời câu hỏi: điều này có giúp ai đó nhìn rõ hơn, sống thật hơn, đi tử tế hơn không?</p><p>Trước khi tạo ra điều tiếp theo, hãy thử dừng lại và hỏi: mình đang muốn được nhìn thấy, hay mình đang thật sự nhìn thấy một điều cần được chăm sóc?</p>',
  '<p>Lasting value does not come from producing more in order to be noticed, but from seeing a real need and bringing forth what truly deserves to exist.</p><p>At a deeper level, creativity begins with clarity. It sees a problem that has not been named, a pain people carry but cannot express, a gap in daily life that content, community, or a program may touch with care. When clarity is present, creativity stops being a performance of the ego and becomes an act of response.</p><p>True needs are often not on the surface. People may ask for motivation when they need rest without guilt. They may ask for communication skills when they need courage to speak truth respectfully. They may ask for success when they need a definition of success that does not betray health, family, and dignity.</p><p>Ambition is not the enemy, but it must serve clarity rather than replace it. Đường Sao Tỏa Sáng chooses slow and deep creation: not content made to fill a schedule, but work that helps someone see more clearly, live more truthfully, and move more kindly.</p>',
  '', '', 'sáng tạo,nhận thức', 1,
  '2026-02-26T08:00:00.000Z', '2026-06-07T10:30:00.000Z'
);

INSERT OR REPLACE INTO contents (
  slug, type,
  title, title_vi, title_en,
